assignments.value:
={{ $json.item.map((element) => {
  if ('repeatDefective' in element) {
    return {
      SN: element['repeatDefective']["retroId"],
      Reason: '该设备已有删除记录',
    };
  }
  if ('insertDefective' in element) {
    return {
      SN: element['insertDefective']["retroId"],
      Reason: '该设备删除记录插入失败',
    };
  }
  if ('errActiveItem' in element) {
    return {
      SN: element['errActiveItem']["retroId"],
      Reason: '该设备未激活',
    };
  }
  if ('insertActive' in element) {
    return {
      SN: element['insertActive']["retroId"],
      Reason: '该设备的已取消激活状态打标失败',
    };
  }
  return { SN: null, Reason: '上传成功' };
});

